/* helpers */
function pad(n) { return String(n).padStart(2, "0"); }
function getDaysInMonth(y, m) { return new Date(y, m + 1, 0).getDate(); }
function getFirstDay(y, m) { return (new Date(y, m, 1).getDay() + 1) % 7; }

/* ── Date Picker Component ── */
function DatePicker({ value, onChange }) {
  const today = new Date();
  const [open, setOpen] = useState(false);
  const [vy, setVy] = useState(today.getFullYear());
  const [vm, setVm] = useState(today.getMonth());
  const ref = useRef(null);

  let selD = null, selM = null, selY = null;
  if (value) {
    const p = value.split("/");
    if (p.length === 3) { selD = +p[0]; selM = +p[1] - 1; selY = +p[2]; }
  }

  useEffect(() => {
    const h = (e) => { if (ref.current && !ref.current.contains(e.target)) setOpen(false); };
    document.addEventListener("mousedown", h);
    return () => document.removeEventListener("mousedown", h);
  }, []);

  const prev = () => { if (vm === 0) { setVm(11); setVy(y => y-1); } else setVm(m => m-1); };
  const next = () => { if (vm === 11) { setVm(0); setVy(y => y+1); } else setVm(m => m+1); };
  const pick = (d) => { onChange(`${pad(d)}/${pad(vm+1)}/${vy}`); setOpen(false); };

  const dim = getDaysInMonth(vy, vm);
  const first = getFirstDay(vy, vm);
  const cells = [...Array(first).fill(null), ...Array.from({length: dim}, (_,i) => i+1)];

  return (
    <div className="cal-wrap" ref={ref}>
      <button type="button" className="date-trigger" onClick={() => setOpen(o=>!o)}>
        {value ? <span>{value}</span> : <span className="date-placeholder">اختر التاريخ</span>}
      </button>
      {open && (
        <div className="cal-dropdown">
          <div className="cal-nav">
            <button className="cal-nav-btn" onClick={next}>›</button>
            <div>{AR_MONTHS[vm]} {vy}</div>
            <button className="cal-nav-btn" onClick={prev}>‹</button>
          </div>
          <div className="cal-days-header">
            {AR_DAYS.map(d => <div className="cal-day-header" key={d}>{d}</div>)}
          </div>
          <div className="cal-grid">
            {cells.map((d, i) => (
              <div key={i} className={["cal-cell", !d?"empty":"", d && d===selD && vm===selM && vy===selY?"selected":""].join(" ")} onClick={() => d && pick(d)}>
                {d || ""}
              </div>
            ))}
          </div>
        </div>
      )}
    </div>
  );
}

function InputField({ label, labelEn, value, onChange }) {
  return (
    <div className="field-group">
      <label className="field-label">{label}<span className="field-label-en">{labelEn}</span></label>
      <input type="text" className="field-input" placeholder={label} value={value} onChange={(e) => onChange(e.target.value)} />
    </div>
  );
}

/* ── Main Component ── */
export default function CertificateForm({ user, onLogout }) {
  const [activeTab, setActiveTab] = useState("export"); // تابات: 'export' أو 'reports'
  const [data, setData] = useState(defaultData);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState(null);
  const [processing, setProcessing] = useState(false);

  // دول للحالة الخاصة بالتقارير
  const [reports, setReports] = useState([]);
  const [searchQuery, setSearchQuery] = useState("");

  const set = (key) => (val) => setData(d => ({ ...d, [key]: val }));

  useEffect(() => {
    if (message) {
      const t = setTimeout(() => setMessage(null), 3000);
      return () => clearTimeout(t);
    }
  }, [message]);

  // جلب التقارير من السيرفر عند فتح تاب التقارير
  useEffect(() => {
    if (activeTab === "reports") {
      fetchReports();
    }
  }, [activeTab]);

  const fetchReports = async () => {
    const token = sessionStorage.getItem("token");
    try {
      const res = await fetch(`${API_BASE}/certificates`, {
        headers: { "Authorization": token }
      });
      const result = await res.json();
      if (result.success) {
        setReports(result.data);
      }
    } catch (err) {
      console.error("Error fetching reports:", err);
    }
  };

  const handleSave = async () => {
    const token = sessionStorage.getItem("token");
    if (!token) {
      setMessage({ type: "error", text: "يرجى تسجيل الدخول" });
      return false;
    }
    setSaving(true);
    try {
      const res = await fetch(`${API_BASE}/certificates`, {
        method: "POST",
        headers: { "Content-Type": "application/json", "Authorization": token },
        body: JSON.stringify(data),
      });
      if (res.status === 401) {
        setMessage({ type: "error", text: "انتهت الجلسة، يرجى تسجيل الدخول" });
        return false;
      }
      const result = await res.json();
      if (result.success) {
        setMessage({ type: "success", text: result.message });
        return true;
      } else {
        setMessage({ type: "error", text: result.message || "فشل حفظ البيانات" });
        return false;
      }
    } catch (err) {
      setMessage({ type: "error", text: "خطأ في الاتصال بالسيرفر" });
      return false;
    } finally {
      setSaving(false);
    }
  };

  const exportPDF = async (data) => {
    const canvas = document.createElement("canvas");
    canvas.width = ORIG_W * 4; canvas.height = ORIG_H * 4;
    const ctx = canvas.getContext("2d");
    try {
      const params = new URLSearchParams({
        no: data.certificateNo || "", dt: data.date || "", sn: data.serialNumber || "",
        aw: data.alloyWeight || "", ac: data.alloyCarat || "", nw: data.netWeight || "",
      });
      const qrData = `https://albarq.kian24.com/verify.html?${params.toString()}`;
      const qrUrl = await QRCode.toDataURL(qrData, { width: 340, margin: 1, errorCorrectionLevel: "M" });

      const [bgImg, qrImg] = await Promise.all([
        loadImage(`data:image/png;base64,${CERT_IMG_BASE64}`),
        loadImage(qrUrl)
      ]);

      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      ctx.fillStyle = "#1a2a4a"; ctx.textBaseline = "middle";

      FIELDS.forEach(({ key, top, left, width, height, fontSize }) => {
        const val = data[key]; if (!val) return;
        ctx.font = `700 ${fontSize * 4}px Tajawal, Arial, sans-serif`;
        ctx.textAlign = "center";
        ctx.fillText(val, (left + width / 2) * 4, (top + height / 2) * 4);
      });

      ctx.fillStyle = "#FFFFFF";
      ctx.fillRect(25 * 4, 100 * 4, 110 * 4, 110 * 4);
      ctx.drawImage(qrImg, 35 * 4, 110 * 4, 90 * 4, 90 * 4);

      const imgData = canvas.toDataURL("image/png", 0.96);
      const pdf = new jsPDF({ orientation: "portrait", unit: "mm", format: "a4", compress: true });
      pdf.addImage(imgData, "PNG", 10, 2, 120, 70, "", "FAST");
      pdf.save(`شهادة-${data.certificateNo || 'وزن'}.pdf`);
    } catch (error) {
      console.error(error);
    }
  };

  const handleExportAndSave = async () => {
    const hasData = Object.values(data).some(x => x?.trim());
    if (!hasData) {
      setMessage({ type: "error", text: "يرجى ملء بعض البيانات قبل التصدير" });
      return;
    }
    setProcessing(true);
    try {
      const saveSuccess = await handleSave();
      if (!saveSuccess) return;
      await exportPDF(data);
      setData(defaultData);
    } catch (error) {
      console.error(error);
    } finally {
      setProcessing(false);
    }
  };

  // دالة تصدير تقرير التقارير المفلترة لـ PDF كجدول منسق
const exportReportToPDF = async () => {
  // 1. إظهار صندوق إدخال للمستخدم ليدخل رقم الشهادة أو الشحنة
  const userInput = prompt("الرجاء إدخال رقم الشهادة أو الشحنة لتصديرها:");
  
  // إذا ألغى المستخدم الإدخال أو تركه فارغاً
  if (!userInput || userInput.trim() === "") {
    alert("لم يتم إدخال أي رقم، تم إلغاء التصدير.");
    return;
  }

  const targetNo = userInput.trim();

  // 2. الفلترة للبحث عن الشهادات المطابقة للرقم المدخل
  const matchedReports = filteredReports.filter(r => 
    String(r.certificate_no) === targetNo || 
    (r.batch_no && String(r.batch_no) === targetNo)
  );

  if (matchedReports.length === 0) {
    alert("عذراً، لم يتم العثور على أي شهادات مطابقة لهذا الرقم.");
    return;
  }

  // معرفة ما إذا كانت المخرجات عبارة عن شحنة تحتوي على أكثر من شهادة
  const isBatch = matchedReports.length > 1;

  // 3. تجهيز كائن الـ PDF العام (Portrait - A4)
  const pdf = new jsPDF({ 
    orientation: "portrait", 
    unit: "mm", 
    format: "a4", 
    compress: true 
  });

  try {
    // تحميل صورة الخلفية الفاخرة للشهادة مرة واحدة فقط
    const bgImg = await loadImage(`data:image/png;base64,${CERT_IMG_BASE64}`);

    // 4. الدوران على الشهادات المفلترة لطباعتها وراء بعض بنفس الشكل
    for (let i = 0; i < matchedReports.length; i++) {
      const report = matchedReports[i];

      // تحويل أسماء الحقول من الـ Database إلى الأسماء المتوقعة في دالة الرسم والـ QR
      const data = {
        certificateNo: report.certificate_no,
        date: report.date,
        serialNumber: report.serial_number,
        alloyWeight: report.alloy_weight,
        alloyCarat: report.alloy_carat,
        netWeight: report.net_weight
      };

      // إضافة صفحة جديدة لكل شهادة إضافية في الشحنة
      if (i > 0) {
        pdf.addPage();
      }

      // إنشاء الكانفاس الخاص بالشهادة الحالية بالدقة العالية (4x)
      const canvas = document.createElement("canvas");
      canvas.width = ORIG_W * 4; 
      canvas.height = ORIG_H * 4;
      const ctx = canvas.getContext("2d");

      // توليد الـ QR كود المستقل والخاص بالشهادة الحالية
      const params = new URLSearchParams({
        no: data.certificateNo || "", 
        dt: data.date || "", 
        sn: data.serialNumber || "",
        aw: data.alloyWeight || "", 
        ac: data.alloyCarat || "", 
        nw: data.netWeight || "",
      });
      
      const qrData = `https://albarq.kian24.com/certificate-project/verify.html?${params.toString()}`;
      const qrUrl = await QRCode.toDataURL(qrData, { width: 340, margin: 1, errorCorrectionLevel: "M" });
      const qrImg = await loadImage(qrUrl);

      // رسم الخلفية الأصلية الفاخرة للشهادة
      ctx.drawImage(bgImg, 0, 0, canvas.width, canvas.height);
      ctx.fillStyle = "#1a2a4a"; 
      ctx.textBaseline = "middle";

      // ── تعديل الارتفاع العمودي ليتناسب وينزل تحت شوية ──
      if (isBatch) {
        ctx.font = `700 ${18 * 4}px Tajawal, Arial, sans-serif`; 
        ctx.textAlign = "center";
        
        const serialField = FIELDS.find(f => f.key === 'serialNumber');
        
        let numberX = 260 * 4; 
        if (serialField) {
          numberX = (serialField.left + (serialField.width / 2)) * 4;
        }
        
        // تم زيادة القيمة هنا إلى 72 لتنزيل الترقيم ليكون فوق جدول الرقم المتسلسل طوالي
        const numberY = 106 * 4; 
        
        ctx.fillText(String(i + 1), numberX, numberY);
      }
      // ───────────────────────────────────────────────────

      // توزيع النصوص على الخلايا والأبعاد الهندسية المحددة في FIELDS
      FIELDS.forEach(({ key, top, left, width, height, fontSize }) => {
        const val = data[key]; 
        if (!val) return;
        ctx.font = `700 ${fontSize * 4}px Tajawal, Arial, sans-serif`;
        ctx.textAlign = "center";
        ctx.fillText(val, (left + width / 2) * 4, (top + height / 2) * 4);
      });

      // رسم مربع الخلفية الأبيض والـ QR كود فوقه لكل شهادة بشكل نظيف
      ctx.fillStyle = "#FFFFFF";
      ctx.fillRect(25 * 4, 100 * 4, 110 * 4, 110 * 4);
      ctx.drawImage(qrImg, 35 * 4, 110 * 4, 90 * 4, 90 * 4);

      // تحويل الكانفاس الحالي لصورة بجودة مرتفعة وضغط ممتاز
      const imgData = canvas.toDataURL("image/png", 0.96);
      
      // إسقاط صورة الشهادة على صفحة الـ PDF بأبعاد الـ mm الصحيحة
      pdf.addImage(imgData, "PNG", 10, 2, 120, 70, "", "FAST");
    }

    // 5. تسمية ملف الـ PDF وحفظه
    const finalFileName = isBatch 
      ? `تقرير_شحنة_رقم_${targetNo}`
      : `شهادة_رقم_${targetNo}`;

    pdf.save(`${finalFileName}.pdf`);

  } catch (error) {
    console.error("حدث خطأ أثناء تصدير التقرير:", error);
    alert("عذراً، حدث خطأ أثناء معالجة ملف الـ PDF.");
  }
};

  const loadImage = (src) => new Promise((resolve, reject) => {
    const img = new Image(); img.onload = () => resolve(img); img.onerror = reject; img.src = src;
  });

  // تصفية التقارير بناءً على رقم الشهادة في البحث
  const filteredReports = reports.filter(r => 
    r.certificate_no.toLowerCase().includes(searchQuery.toLowerCase())
  );

  // حساب تكرار أرقام الشهادات لمعرفة الشحنات المشتركة
  const certCounts = filteredReports.reduce((acc, cur) => {
    acc[cur.certificate_no] = (acc[cur.certificate_no] || 0) + 1;
    return acc;
  }, {});

  const initials = (user?.full_name || user?.username || "?").split(" ").map(w => w[0]).slice(0,2).join("");

  return (
    <>
      <style>{styles}</style>
      <div className="cert-root">
        {/* Topbar */}
        <div className="topbar">
          <div className="topbar-left">
            <div className="user-chip">
              <div className="user-avatar">{initials}</div>
              <span className="user-name">مرحباً، {user?.full_name || user?.username}</span>
            </div>
          </div>
          <div className="topbar-right">
            <button className="logout-btn" onClick={onLogout}>تسجيل خروج</button>
          </div>
        </div>
        <div className="topbar-accent" />

        {/* Navigation Tabs */}
        <div className="cert-body" style={{paddingBottom: "10px"}}>
          <div className="tabs-container">
            <button className={`tab-btn ${activeTab === "export" ? "active" : ""}`} onClick={() => setActiveTab("export")}>
                الشهادات
            </button>
            <button className={`tab-btn ${activeTab === "reports" ? "active" : ""}`} onClick={() => setActiveTab("reports")}>
              التقارير 
            </button>
          </div>
        </div>

        {/* Main Body content changes based on tab */}
        <div className="cert-body" style={{paddingTop: "0px"}}>
          {activeTab === "export" ? (
            <div className="form-card-wrap">
              <div className="form-card">
                <div className="form-section-title">بيانات الشهادة الجديدة</div>
                <InputField label="رقم الشهادة" labelEn="Certificate No." value={data.certificateNo} onChange={set("certificateNo")} />
                <div className="field-group">
                  <label className="field-label">التاريخ<span className="field-label-en">Date</span></label>
                  <DatePicker value={data.date} onChange={set("date")} />
                </div>
                <InputField label="الرقم المتسلسل" labelEn="Serial Number" value={data.serialNumber} onChange={set("serialNumber")} />
                <InputField label="وزن السبيكة" labelEn="Alloy Weight" value={data.alloyWeight} onChange={set("alloyWeight")} />
                <InputField label="عيار السبيكة" labelEn="Alloy Carat" value={data.alloyCarat} onChange={set("alloyCarat")} />
                <InputField label="الوزن الصافي بالجرام" labelEn="Net Weight (g)" value={data.netWeight} onChange={set("netWeight")} />

                <div className="action-row">
                  <button className="btn-export" onClick={handleExportAndSave} disabled={processing || saving}>
                    {processing || saving ? "جاري الحفظ والتصدير..." : "تصدير PDF وحفظ"}
                  </button>
                </div>
                {message && (
                  <div className={`toast ${message.type === "success" ? "toast-success" : "toast-error"}`}>
                    {message.text}
                  </div>
                )}
              </div>
            </div>
          ) : (
            // ─── شاشة التقارير الحالية ───
            <div className="report-card-wrap">
              <div className="form-card">
                <div style={{display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '20px'}}>
                  <div className="form-section-title" style={{margin: 0}}>  </div>
                  <button className="btn-save" onClick={exportReportToPDF}>تصدير التقرير  PDF</button>
                </div>


                {/* حقل البحث */}
                <input 
                  type="text" 
                  className="field-input search-box" 
                  placeholder=" ابحث برقم الشهادة   ..." 
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                />

                <div className="report-table-wrapper">
                  <table className="report-table">
                    <thead>
                      <tr>
                        <th>رقم الشهادة</th>
                        <th>حالة الشحن</th>
                        <th>التاريخ</th>
                        <th>الرقم المتسلسل</th>
                        <th>وزن السبيكة</th>
                        <th>العيار</th>
                        <th>الوزن الصافي</th>
                      </tr>
                    </thead>
                    <tbody>
                      {filteredReports.length === 0 ? (
                        <tr>
                          <td colSpan="7" style={{textAlign: 'center', padding: '20px'}}>لا توجد سجلات مطابقة للبحث.</td>
                        </tr>
                      ) : (
                        filteredReports.map((report, index) => {
                          const isSharedBatch = certCounts[report.certificate_no] > 1;
                          return (
                            <tr key={report.id} className={isSharedBatch ? "batch-row" : ""}>
                              <td style={{fontWeight: 'bold', color: '#7a5c18'}}>{report.certificate_no}</td>
                              <td>
                                {isSharedBatch ? (
                                  <span className="batch-badge">شحنة موحدة</span>
                                ) : (
                                  <span style={{color: '#888', fontSize: '12px'}}>منفردة</span>
                                )}
                              </td>
                              <td>{report.date}</td>
                              <td>{report.serial_number}</td>
                              <td>{report.alloy_weight}</td>
                              <td>{report.alloy_carat}</td>
                              <td>{report.net_weight}</td>
                            </tr>
                          );
                        })
                      )}
                    </tbody>
                  </table>
                </div>

              </div>
            </div>
          )}
        </div>
      </div>
    </>
  );
}